Este es el primer ejemplo de código usando  p5.js integrado en un post con Hugo. Debajo del sketch está el código que lo genera.
   Sketch interactivo del archivo helloWorld.js:  Al ver el código, veréis que tiene un par de funciones más que el clásico HelloWorld:
 getPos(&hellip;):el canvas (lienzo) se coloca dentro de un elemento  div id=&ldquo;sketch&rdquo;. Esta función me devuelve en coordenadas absolutas la posición de ese div. Me va a ayudar para la siguiente función. centerCanvasDivHorizontally(): esta función me centra el canvas horizontalmente dependiendo del tamaño del mismo. Lo he desarrollado para que al ejecutarse la anchura sea 3/4 de la anchura de la ventana. Al final de la función modifico directamente el CSS del div que lo contiene para asegurar que los bordes se vean adecuadamente.   Código del archivo helloWorld.js: //Funciones auxiliares para centrar el canvas en la pantalla: let canvas, canvasDiv; //Funcion para lograr la posicion absoluta de mi contenedor function getPos(el) { // yay readability for (var lx=0, ly=0; el != null; lx += el.offsetLeft, ly += el.offsetTop, el = el.offsetParent); return {x: lx,y: ly}; } //Quiero que centre el canvas solo horizontaltmente function centerCanvasDivHorizontally() { var xCenter = (windowWidth - width) / 2; var yCenter = (windowHeight - height) / 2; var posDiv = getPos(canvasDiv); /*console.log(&quot;Pos Div: &quot;, posDiv); console.log(&quot;width: &quot;, width); console.log(&quot;height: &quot;, height); */ //Hacemos que el canvas esté contenido en el div 'sketch' canvas.parent('sketch'); //Aquí vamos a mover un poquito el sketch en horizontal hacia la izquierda para que quede centrado en la página. moveToLeft = (xCenter - posDiv.x); canvasDiv.setAttribute(&quot;style&quot;,&quot; margin: 0; padding: 0; width:&quot; + width + &quot;px; height:&quot; + height + &quot;px; margin-left:&quot; + moveToLeft + &quot;px; overflow: hidden;&quot;); } function setup() { canvasDiv = document.getElementById('sketch'); sWidth = windowWidth*3/4; sHeight = sWidth * 9 / 16; canvas = createCanvas(sWidth,sHeight); centerCanvasDivHorizontally(); } function draw() { //Dibujo el borde del canvas: //background(0,0,0); fill(random(255), random(255), random(255)); } function mouseMoved() { ellipse(mouseX, mouseY, 80, 80); }
